import React, { useState } from 'react';

const FAQ = ({ content = {} }) => {
  // Always call hooks first
  const [openIndex, setOpenIndex] = useState(null);

  // Guard against undefined/null content - render null after hooks
  if (!content || typeof content !== 'object') {
    return null;
  }

  const { title = 'Questions Fréquentes', items = [] } = content;

  // Guard against invalid items
  if (!Array.isArray(items) || items.length === 0) {
    return null;
  }

  const toggle = (index) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  return (
    <section className="faq-section" data-faq="true">
      <div className="container">
        <h2>{title}</h2>
        <div className="faq-list">
          {items.map((item, index) => {
            // Guard against invalid item
            if (!item || typeof item !== 'object') {
              return null;
            }
            return (
              <div key={index} className={`faq-item ${openIndex === index ? 'open' : ''}`}>
                <button className="faq-question" onClick={() => toggle(index)}>
                  <span>{item.question || 'Question'}</span>
                  <span className="faq-icon">{openIndex === index ? '−' : '+'}</span>
                </button>
                {openIndex === index && (
                  <div className="faq-answer">
                    <p>{item.answer || ''}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
};

export default FAQ;
